CustomField.formula:
IF(
   (Dias_a_la_vigencia__c  >=  1 && Dias_a_la_vigencia__c <= 30), "a. 1 a 30",
   IF(
      (Dias_a_la_vigencia__c  >  30 && Dias_a_la_vigencia__c <= 60), "b. 31 a 60",
      IF((Dias_a_la_vigencia__c  >  60 && Dias_a_la_vigencia__c <= 90), "c. 61 a 90",
         IF( (Dias_a_la_vigencia__c  >  90 && Dias_a_la_vigencia__c <= 120), "d. 91 a 120", 
            IF( (Dias_a_la_vigencia__c  >  120 && Dias_a_la_vigencia__c <= 180), "e. 120 a 180", "f. Más de 180"
            )
         )
      )  
   )
)
